#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *pa = *(int **)a;
    int *pb = *(int **)b;
    if (pa[0] != pb[0]) return pa[0] - pb[0];
    return pa[1] - pb[1];
}

int judge(int **pairs) {
    return (pairs[0][0] < pairs[3][0] && pairs[3][0] < pairs[5][0] &&
            pairs[0][1] < pairs[1][1] && pairs[1][1] < pairs[2][1] &&
            pairs[0][0] == pairs[1][0] && pairs[1][0] == pairs[2][0] &&
            pairs[3][0] == pairs[4][0] &&
            pairs[5][0] == pairs[6][0] && pairs[6][0] == pairs[7][0] &&
            pairs[0][1] == pairs[5][1] &&
            pairs[1][1] == pairs[6][1] &&
            pairs[2][1] == pairs[7][1] &&
            pairs[0][1] == pairs[3][1] &&
            pairs[2][1] == pairs[4][1]);
}

int main() {
    int **pairs = malloc(8 * sizeof(int *));
    for (int i = 0; i < 8; i++) {
        pairs[i] = malloc(2 * sizeof(int));
        scanf("%d %d", &pairs[i][0], &pairs[i][1]);
    }
    qsort(pairs, 8, sizeof(int *), compare);

    if (judge(pairs)) {
        printf("respectable\n");
    } else {
        printf("ugly\n");
    }

    for (int i = 0; i < 8; i++) {
        free(pairs[i]);
    }
    free(pairs);
    return 0;
}
